import pytest
import requests

MAX_COMPONENTS = 100

def test_observation_at_max_component_count_boundary_accepted(
    base_url, registered_device_cert
):
    components = [
        {
            "code": {"coding": [{"system": "http://loinc.org", "code": f"000{i}-{i}"}]},
            "valueQuantity": {"value": i, "unit": "unit"}
        }
        for i in range(MAX_COMPONENTS)
    ]
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {"coding": [{"system": "http://loinc.org", "code": "85353-1"}]},
        "subject": {"reference": "Patient/test-patient-001"},
        "effectiveDateTime": "2024-01-15T10:00:00Z",
        "component": components
    }
    resp = requests.post(
        f"{base_url}/Ingest",
        json=payload,
        cert=registered_device_cert,
        timeout=15
    )
    assert resp.status_code == 201, f"Expected 201, got {resp.status_code}: {resp.text}"
    body = resp.json()
    stored_count = len(body.get("component", []))
    assert stored_count == MAX_COMPONENTS, \
        f"Expected {MAX_COMPONENTS} components stored, got {stored_count}"
